NP_functionality.VERILOG_PROVIDED:
`ifndef _SIM_HAVE_CLOG2
  function integer log2;
     input integer value;
     integer temp_value;
    begin
      temp_value = value-1;
      for (log2=0; temp_value>0; log2=log2+1)
        temp_value = temp_value>>1;
    end
  endfunction
`endif
`ifdef _SIM_HAVE_CLOG2
  localparam QUEUESIZE_LOG = $clog2(FIFO_DEPTH);
`else
  localparam QUEUESIZE_LOG = log2(FIFO_DEPTH);
`endif

reg [QUEUESIZE_LOG:0] read_idx, write_idx;
wire wrap;
assign wrap = write_idx[QUEUESIZE_LOG] ^ read_idx[QUEUESIZE_LOG];
assign empty_n = (write_idx == read_idx) ? 1'b0 : 1'b1;

always @(posedge clock 1RESET_EDGE)
begin
  if (1RESET_VALUE)
  begin
    read_idx <= 0;
    write_idx <= 0;
  end
  else
  begin
    if (write == 1'b1)
    begin
      write_idx <= write_idx + 1'b1;
    end
    if (read == 1'b1)
    begin
      read_idx <= read_idx + 1'b1;
    end
  end
end

generate
  if(FIFO_DEPTH < 2)
  begin : scope_lessthan2
    reg [BITSIZE_din-1:0] circ_fifo;
    assign dout = circ_fifo;
    assign full_n = wrap ? 1'b0 : 1'b1;
    always @(posedge clock)
    begin
      if (write == 1'b1)
      begin
        circ_fifo <= din;
      end
    end
  end
  else
  begin : scope_else
    reg [BITSIZE_din-1:0] circ_fifo [0:((1<<QUEUESIZE_LOG)-1)];
    assign full_n = (wrap && (write_idx[QUEUESIZE_LOG-1:0] == read_idx[QUEUESIZE_LOG-1:0])) ? 1'b0 : 1'b1;
    assign dout = circ_fifo[read_idx[QUEUESIZE_LOG-1:0]];
    always @(posedge clock)
    begin
      if (write == 1'b1)
      begin
        circ_fifo[write_idx[QUEUESIZE_LOG-1:0]] <= din;
      end
    end
  end
endgenerate
